SELECT title
FROM pull_requests
ORDER BY created_at DESC;

SELECT COUNT(*) AS total_closed_pull_requests 
FROM pull_requests 
WHERE state = 'closed';

SELECT title
FROM pull_requests
WHERE state = 'closed';

SELECT AVG(review_time) AS average_review_time
FROM analytics
WHERE reviewer_id = 1;

SELECT repository_id, COUNT(id) AS pull_request_count
FROM pull_requests
GROUP BY repository_id;
